import{_ as t,o as r,c as o,an as a}from"./chunks/framework.ubcH7j8_.js";const g=JSON.parse('{"title":"Platform Overview","description":"End-to-end snapshot of the A.R.C. landing experience in documentation form.","frontmatter":{"title":"Platform Overview","description":"End-to-end snapshot of the A.R.C. landing experience in documentation form."},"headers":[],"relativePath":"ard/platform-overview.md","filePath":"ard/platform-overview.md","lastUpdated":1773164166000}'),n={name:"ard/platform-overview.md"};function i(s,e,l,d,c,u){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="a-r-c-in-one-look" tabindex="-1">A.R.C. In One Look <a class="header-anchor" href="#a-r-c-in-one-look" aria-label="Permalink to &quot;A.R.C. In One Look&quot;">​</a></h1><p><strong>A.R.C. (Agentic Reasoning Core)</strong> is the open-source, distributed intelligence orchestration engine that lets you transform weeks of infrastructure setup into a single command. It is built for teams that want a production-ready &quot;Platform-in-a-Box&quot; without surrendering control of their stack—and who expect every service, codename, and circuit breaker to ship pre-wired.</p><ul><li><strong>Tagline:</strong> An open-source, modular, Platform-in-a-Box for distributed intelligence.</li><li><strong>Focus:</strong> Deliver minutes-to-production workflows, full customizability, and an entirely open-source foundation with chaos-tested resilience.</li><li><strong>Quick Wins:</strong> ⚡ Minutes to deploy · 🔧 Fully customizable · 🌐 Open source · 🛡️ Chaos-ready</li></ul><hr><h2 id="🧠-what-is-a-r-c" tabindex="-1">🧠 What is A.R.C.? <a class="header-anchor" href="#🧠-what-is-a-r-c" aria-label="Permalink to &quot;🧠 What is A.R.C.?&quot;">​</a></h2><p>A.R.C. is a distributed intelligence orchestration engine designed to remove infrastructure friction so you can focus on what your agents think and do. With a single CLI-driven experience you get a cohesive, battle-tested ecosystem that ships all essential services pre-wired and production-hardened. The platform maps business-critical roles to named services so you always know who is guarding the door, minding the logs, or keeping the neural net honest.</p><ul><li>🏗️ <strong>Platform, Not Library:</strong> Compose a complete ecosystem with one command—no manual wiring of services.</li><li>⚡ <strong>Minutes, Not Months:</strong> Go from idea to deployment immediately while A.R.C. handles the plumbing.</li><li>🔧 <strong>Your Stack, Your Rules:</strong> Everything is standards-based and swappable with zero vendor lock-in.</li><li>🧭 <strong>Role-Aware Services:</strong> Heimdall (Traefik) gates ingress, Sherlock (LangGraph) reasons, T-800 (Chaos Mesh) pressure-tests the cluster, and Friday (SigNoz) shows the vitals.</li></ul><hr><h2 id="✨-why-choose-a-r-c" tabindex="-1">✨ Why Choose A.R.C.? <a class="header-anchor" href="#✨-why-choose-a-r-c" aria-label="Permalink to &quot;✨ Why Choose A.R.C.?&quot;">​</a></h2><ul><li><strong>Truly Open-Source:</strong> 100% FOSS (Apache 2.0, MIT, MPL). No BSL, &quot;source-available&quot;, or non-compete traps.</li><li><strong>Platform-in-a-Box:</strong> Heimdall (Traefik), J.A.R.V.I.S. (Kratos), Nick Fury (Infisical), Mystique (Unleash), and more arrive pre-configured.</li><li><strong>Modular &amp; Pluggable:</strong> Extend and swap components while staying on open standards like OpenFeature and OpenTelemetry.</li><li><strong>Polyglot Architecture:</strong> High-performance Go gateway and CLI paired with the Python AI ecosystem for agent logic.</li><li><strong>Cloud-Native:</strong> Containerized, horizontally scalable, and deployable everywhere through a single <code>arc run</code>.</li><li><strong>Event-Driven:</strong> Durable streaming via Dr. Strange (Pulsar) plus real-time messaging with The Flash (NATS).</li><li><strong>Distributed Intelligence:</strong> Build and orchestrate multi-agent systems with Sherlock, Scarlett, Alfred, and Gordon Ramsay working together.</li><li><strong>Stateful Agents:</strong> Persist context with Oracle (Postgres + pgvector) and Sonic (Redis) for semantic recall and hot state.</li><li><strong>Self-Hosted &amp; Resilient:</strong> Own your data, keep everything on-prem if needed, and let the T-800 (Chaos Mesh) validate uptime.</li></ul><hr><h2 id="🛠️-the-a-r-c-journey" tabindex="-1">🛠️ The A.R.C. Journey <a class="header-anchor" href="#🛠️-the-a-r-c-journey" aria-label="Permalink to &quot;🛠️ The A.R.C. Journey&quot;">​</a></h2><ol><li><strong>Design Your Agent</strong> — Define capabilities, context windows, and reasoning patterns declaratively. <em>(Focus: capabilities &amp; reasoning)</em></li><li><strong>Orchestrate Services</strong> — Let A.R.C. auto-compose Heimdall, J.A.R.V.I.S., Mystique, and friends into a cohesive stack. <em>(Benefit: pre-configured infrastructure)</em></li><li><strong>Implement Intelligence</strong> — Ship unique agent logic while Sherlock, RoboCop, and Gordon Ramsay handle reasoning, guardrails, and critique. <em>(Approach: logic over plumbing)</em></li><li><strong>Deploy &amp; Scale</strong> — Launch with built-in monitoring, tracing, chaos drills, and scaling; no DevOps fire drills. <em>(Result: production-ready instantly)</em></li></ol><hr><h2 id="🔍-traditional-vs-the-a-r-c-way" tabindex="-1">🔍 Traditional vs. The A.R.C. Way <a class="header-anchor" href="#🔍-traditional-vs-the-a-r-c-way" aria-label="Permalink to &quot;🔍 Traditional vs. The A.R.C. Way&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Traditional Build</th><th>The A.R.C. Way</th></tr></thead><tbody><tr><td>⏰ Days spent wiring infrastructure</td><td>⚡ Single-command deployment</td></tr><tr><td>🔧 Manual service integration</td><td>🔗 Heimdall + friends pre-integrated</td></tr><tr><td>🔒 Risk of vendor lock-in</td><td>🆓 Open-source freedom</td></tr><tr><td>🐛 Painful debugging cycles</td><td>🔍 Sherlock + Friday trace issues</td></tr><tr><td>📈 Scaling bottlenecks</td><td>🚀 Auto-scaling infrastructure</td></tr><tr><td>👓 Limited observability</td><td>📊 OTEL + SigNoz built in</td></tr><tr><td>💸 High maintenance costs</td><td>💰 Cost-effective operations</td></tr><tr><td>📚 Steep learning curves</td><td>🎯 Production-ready in minutes</td></tr><tr><td>💤 Unknown resilience</td><td>🛡️ Chaos-tested by the T-800</td></tr></tbody></table><p>Timeline comparison: <strong>Days of prep</strong> versus <strong>minutes to prod</strong>.</p><hr><h2 id="🚀-powerful-use-cases" tabindex="-1">🚀 Powerful Use Cases <a class="header-anchor" href="#🚀-powerful-use-cases" aria-label="Permalink to &quot;🚀 Powerful Use Cases&quot;">​</a></h2><ul><li><strong>Voice-First Companions:</strong> Scarlett (voice agent) plus Daredevil (LiveKit) deliver low-latency, human-grade conversations.</li><li><strong>Stateful Research Agents:</strong> Sherlock (LangGraph) and Oracle (Postgres) keep long-running investigations grounded in truth.</li><li><strong>Adversarially Tested Automation:</strong> Ivan Drago (Gym) and the T-800 (Chaos Mesh) stress-test logic and infrastructure before production.</li><li><strong>Scalable AI Platforms:</strong> Use A.R.C. as the foundation for your own AI product suite across microservices and workers.</li></ul><hr><h2 id="📚-get-up-and-running-in-minutes" tabindex="-1">📚 Get Up and Running in Minutes <a class="header-anchor" href="#📚-get-up-and-running-in-minutes" aria-label="Permalink to &quot;📚 Get Up and Running in Minutes&quot;">​</a></h2><p>Dive into the documentation to scaffold your first platform and start composing agents immediately.</p><ul><li><code>arc</code> CLI walkthroughs in <a href="/arc-platform/docs/guide/getting-started.html">the introduction docs</a>.</li><li>Service-by-service breakdown in <a href="https://github.com/arc-framework/arc-platform/blob/main/SERVICE.MD" target="_blank" rel="noreferrer"><code>SERVICE.MD</code></a>.</li><li>End-to-end platform guides in <a href="/arc-platform/docs/services/"><code>docs/stack</code></a>.</li><li>Source code and community support on <a href="https://github.com/arc-framework" target="_blank" rel="noreferrer">GitHub</a>.</li></ul><p>Ready to build? Run <code>arc new</code>, follow the prompts, and launch with <code>arc run</code>. Your production-ready agent platform is one command away.</p>',25)])])}const m=t(n,[["render",i]]);export{g as __pageData,m as default};
